    28→  Interpreter(String fileName) throws IOException {
    29→    parser = new Parser(fileName);
    30→    prog = parser.parseAndCheck();
    31→  }
    32→  
    33→  Interpreter(Parser p) {
    34→    parser = p;
    35→    prog = parser.parseAndCheck();
    36→  }
