     1→/** A visitor class for the syntax checker. Returns normally unless there is a syntax error. On a syntax error, 
     2→  * throws a SyntaxException.
     3→  */
     4→class CheckVisitor implements ASTVisitor<Void> {
     5→  /** Empty symbol table. */
     6→  private static final Empty<Variable> EMPTY_VARS = new Empty<Variable>();
     7→  
     8→  /** Symbol table to detect free variables. */
     9→  PureList<Variable> env;
    10→  
    11→  /** Root form of CheckVisitor. */
    12→  public static final CheckVisitor INITIAL = new CheckVisitor(EMPTY_VARS);
    13→
    14→  CheckVisitor(PureList<Variable> e) { env = e; }
    15→  
    16→  /** Helper method that converts an array to a PureList. */
    17→  public static <T> PureList<T> arrayToList(T[] array) {
    18→    int n = array.length;
    19→    PureList<T> list = new Empty<T>();
    20→    for(int i = n-1; i >= 0; i--) { list = list.cons(array[i]); }
    21→    return list;
    22→  }
    23→  
    24→  /*  Visitor methods. */
    25→  public Void forIntConstant(IntConstant i) { return null; }
    26→  public Void forBoolConstant(BoolConstant b) { return null; }
    27→  public Void forEmptyConstant(EmptyConstant n) { return null; }
    28→  
    29→  public Void forVariable(Variable v) {
    30→    Variable match = env.accept(new LookupVisitor<Variable>(v));
    31→    if (match == null) throw new SyntaxException("variable " + v + " is unbound");
    32→    return null;
    33→  }
    34→
    35→  public Void forPrimFun(PrimFun f) { return null;  }
    36→  
    37→  public Void forUnOpApp(UnOpApp u) {
    38→    u.arg().accept(this);  // mzy throw a SyntaxException
    39→    return null;
    40→  }
    41→  
    42→  public Void forBinOpApp(BinOpApp b) {
    43→    b.arg1().accept(this); // may throw a SyntaxException
    44→    b.arg2().accept(this); // may throw a SyntaxException
    45→    return null;
    46→  }
    47→
    48→  public Void forApp(App a) {
    49→    a.rator().accept(this); // may throw a SyntaxException
    50→    AST[] args = a.args();
    51→    int n = args.length;
    52→    for(int i = 0; i < n; i++) { args[i].accept(this); } // may throw a SyntaxException
    53→    return null;
    54→  }
    55→
    56→  public Void forMap(Map m) {
    57→    // Check for duplicates in Map vars & construct newEnv for Map body
    58→    Variable[] vars = m.vars();
    59→    PureList<Variable> varList = arrayToList(vars);
    60→    varList.accept(AnyDuplicatesVisitor.ONLY);  // may throw a SyntaxException
    61→    int n = vars.length;
    62→    PureList<Variable> newEnv = env;
    63→    for(int i = n-1; i >= 0; i--) { newEnv = newEnv.cons(vars[i]); }  // vars appear in newEnv in same order as code, but this property is unimportant
    64→    m.body().accept(new CheckVisitor(newEnv));  // may throw a SyntaxException
    65→    return null;
    66→  }
