    75→  public Void forLet(Let l) {
    76→    // Check for duplicates in Let vars, check Let rhs's and body using newEnv including let vars
    77→    Variable[] vars = l.vars();
    78→    PureList<Variable> varList = arrayToList(vars);
    79→    varList.accept(AnyDuplicatesVisitor.ONLY);  // may throw a SyntaxException
    80→    AST[] exps = l.exps();
    81→    int n = vars.length;
    82→    PureList<Variable> newEnv = env;
    83→    for(int i = n-1; i >= 0; i--) { newEnv = newEnv.cons(vars[i]); }  // vars appear in newEnv in same order as code
    84→    CheckVisitor newVisitor = new CheckVisitor(newEnv);
    85→    for(int i = 0; i < n; i++) { exps[i].accept(newVisitor); } // may throw a SyntaxException
