    98→/** Singleton visitor that checks for duplicate variables in a symbol table. Returns normally unless an error is found.
    99→  * Throws a SyntaxException on error.
   100→  */
   101→class AnyDuplicatesVisitor implements PureListVisitor<Variable, Void> {
   102→  /** Singleton instance. */
   103→  public static AnyDuplicatesVisitor ONLY = new AnyDuplicatesVisitor();
   104→  private AnyDuplicatesVisitor() { }
   105→  
   106→  /* Visitor methods. */
   107→  public Void forEmpty(Empty<Variable> e) { return null; }
   108→
   109→  public Void forCons(Cons<Variable> c) {
   110→    if (c.rest().contains(c.first()))
