/** Type hierarchy for Typed Jam */
interface JamType {}

/** The primitive type 'int'. Singleton. */
class IntType implements JamType {
  public static final IntType ONLY = new IntType();
  private IntType() {}
  public String toString() { return "int"; }
  public boolean equals(Object o) { return o == this; }
}

/** The primitive type 'bool'. Singleton. */
class BoolType implements JamType {
  public static final BoolType ONLY = new BoolType();
  private BoolType() {}
  public String toString() { return "bool"; }
  public boolean equals(Object o) { return o == this; }
}

/** The primitive type 'unit'. Singleton. */
class UnitType implements JamType {
  public static final UnitType ONLY = new UnitType();
  private UnitType() {}
  public String toString() { return "unit"; }
  public boolean equals(Object o) { return o == this; }
}

/** The list type 'list T'. */
class ListType implements JamType {
  private JamType elemType;
  ListType(JamType t) { elemType = t; }
  public JamType elemType() { return elemType; }
  public String toString() { return "list " + elemType; }
  public boolean equals(Object o) {
    if (!(o instanceof ListType)) return false;
    return elemType.equals(((ListType) o).elemType);
  }
  public int hashCode() { return elemType.hashCode() + 1; }
}

/** The reference type 'ref T'. */
class RefType implements JamType {
  private JamType elemType;
  RefType(JamType t) { elemType = t; }
  public JamType elemType() { return elemType; }
  public String toString() { return "ref " + elemType; }
  public boolean equals(Object o) {
    if (!(o instanceof RefType)) return false;
    return elemType.equals(((RefType) o).elemType);
  }
  public int hashCode() { return elemType.hashCode() + 2; }
}

/** The function type '(T1,...,Tn -> T)'. */
class FunType implements JamType {
  private JamType[] paramTypes;
  private JamType returnType;
  FunType(JamType[] pt, JamType rt) { paramTypes = pt; returnType = rt; }
  public JamType[] paramTypes() { return paramTypes; }
  public JamType returnType() { return returnType; }
  public String toString() {
    StringBuilder sb = new StringBuilder("(");
    for (int i = 0; i < paramTypes.length; i++) {
      if (i > 0) sb.append(", ");
      sb.append(paramTypes[i]);
    }
    sb.append(" -> ").append(returnType).append(")");
    return sb.toString();
  }
  public boolean equals(Object o) {
    if (!(o instanceof FunType)) return false;
    FunType other = (FunType) o;
    if (paramTypes.length != other.paramTypes.length) return false;
    for (int i = 0; i < paramTypes.length; i++) {
      if (!paramTypes[i].equals(other.paramTypes[i])) return false;
    }
    return returnType.equals(other.returnType);
  }
  public int hashCode() { return returnType.hashCode() + paramTypes.length; }
}

/** AST class definitions */

/** The AST type which support a visitor interface */
interface AST {
  public <ResType> ResType accept(ASTVisitor<ResType> v);
}

interface ASTVisitor<ResType> {
  ResType forBoolConstant(BoolConstant b);
