    for (int i = 0; i < vars.length; i++) {
      if (i > 0) sb.append(", ");
      sb.append(vars[i]);
      if (varTypes != null && varTypes[i] != null) sb.append(": ").append(varTypes[i]);
    }
    return sb + " to " + body;
  }
}

